```typescript
import { describe, it, expect } from 'vitest';
import { validateEmail } from './validateEmail';

describe('validateEmail', () => {
  // 正常情况
  describe('valid emails', () => {
    it('should return true for standard email', () => {
      expect(validateEmail('user@example.com')).toBe(true);
    });

    it('should return true for email with subdomain', () => {
      expect(validateEmail('user@mail.example.com')).toBe(true);
    });

    it('should return true for email with numbers', () => {
      expect(validateEmail('user123@example.com')).toBe(true);
    });
  });

  // 边界情况
  describe('edge cases', () => {
    it('should return false for empty string', () => {
      expect(validateEmail('')).toBe(false);
    });

    it('should return false for null', () => {
      expect(validateEmail(null as any)).toBe(false);
    });

    it('should return false for undefined', () => {
      expect(validateEmail(undefined as any)).toBe(false);
    });

    it('should return false for email without @', () => {
      expect(validateEmail('userexample.com')).toBe(false);
    });

    it('should return false for email with multiple @', () => {
      expect(validateEmail('user@@example.com')).toBe(false);
    });

    it('should return false for email without domain', () => {
      expect(validateEmail('user@')).toBe(false);
    });

    it('should return false for email without local part', () => {
      expect(validateEmail('@example.com')).toBe(false);
    });
  });

  // 特殊字符
  describe('special characters', () => {
    it('should return false for email with spaces', () => {
      expect(validateEmail('user @example.com')).toBe(false);
    });

    it('should return true for email with dot in local part', () => {
      expect(validateEmail('user.name@example.com')).toBe(true);
    });

    it('should return true for email with plus sign', () => {
      expect(validateEmail('user+tag@example.com')).toBe(true);
    });
  });

  // 性能测试
  describe('performance', () => {
    it('should handle very long email', () => {
      const longEmail = 'a'.repeat(100) + '@example.com';
      expect(() => validateEmail(longEmail)).not.toThrow();
    });
  });
});
